import React from 'react';
import swe1 from '../assets/swe1.jpg';
import swe2 from '../assets/swe2.jpg';
import swe3 from '../assets/swe3.jpg';
import dsc1 from '../assets/dsc1.jpg';
import dsc2 from '../assets/dsc2.jpg';
import dsc3 from '../assets/dsc3.jpg';
import spartan from '../assets/spartan.jpg';
import spartan2 from '../assets/spartan2.jpg';
import img4361 from '../assets/img4361.jpg';
import img4362 from '../assets/img4362.jpg';
import img4363 from '../assets/img4363.jpg';
import './Involvement.css';

const photos = [
  { photo: dsc1,    org: 'Responsible Computing Club', roles: ['Mozilla & Firefox Ambassador', 'VP of External Affairs', 'Community Engagement Lead'] },
  { photo: dsc2,    org: 'Responsible Computing Club', roles: ['Mozilla & Firefox Ambassador', 'VP of External Affairs', 'Community Engagement Lead'] },
  { photo: dsc3,    org: 'Responsible Computing Club', roles: ['Mozilla & Firefox Ambassador', 'VP of External Affairs', 'Community Engagement Lead'] },
  { photo: swe1,    org: 'Society of Women Engineers', roles: ['Alumni Relations Committee Chair', 'Mentorship Committee Chair', 'SWE++ Program Volunteer'] },
  { photo: swe2,    org: 'Society of Women Engineers', roles: ['Alumni Relations Committee Chair', 'Mentorship Committee Chair', 'SWE++ Program Volunteer'] },
  { photo: swe3,    org: 'Society of Women Engineers', roles: ['Alumni Relations Committee Chair', 'Mentorship Committee Chair', 'SWE++ Program Volunteer'] },
  { photo: img4361, org: 'CAPISE', roles: ['Asian Pacific Islander Empower Mentor'] },
  { photo: img4362, org: 'CAPISE', roles: ['Asian Pacific Islander Empower Mentor'] },
  { photo: img4363, org: 'CAPISE', roles: ['Asian Pacific Islander Empower Mentor'] },
  { photo: spartan, org: 'Spartan Racing Formula SAE', roles: ['Business Team Intern'] },
  { photo: spartan2,org: 'Spartan Racing Formula SAE', roles: ['Business Team Intern'] },
];

export default function Involvement() {
  return (
    <section id="involvement" className="involvement-section">
      <div className="inner">
        <span className="section-label reveal">On Campus</span>
        <h2 className="section-title reveal d1">Involvement</h2>

        <div className="inv-grid reveal d2">
          {photos.map((p, i) => (
            <div className="inv-card" key={i}>
              <img src={p.photo} alt={p.org} />
              <div className="inv-overlay">
                <div className="inv-org">{p.org}</div>
                <div className="inv-divider" />
                <div className="inv-roles">
                  {p.roles.map((r) => (
                    <span key={r}>{r}</span>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
